import json
from openai import OpenAI

client = OpenAI()

TOOLS = [
    {
        'type': 'function',
        'function': {
            'name': 'get_weather',
            'description': 'Return current temperature for a city.',
            'parameters': {
                'type': 'object',
                'properties': {
                    'city': {'type': 'string', 'description': 'City name, e.g. Berlin'},
                },
                'required': ['city'],
            },
        },
    }
]

def get_weather(city: str) -> dict:
    # Stub: replace with a real weather API call
    return {'city': city, 'temperature_c': 18, 'condition': 'partly cloudy'}

def run_with_tools(user_query: str) -> str:
    messages = [{'role': 'user', 'content': user_query}]

    while True:
        response = client.chat.completions.create(
            model='gpt-4o-mini',
            messages=messages,
            tools=TOOLS,
            tool_choice='auto',
            max_tokens=512,
        )
        choice = response.choices[0]

        if choice.finish_reason == 'tool_calls':
            # Append assistant message (contains tool_calls array)
            messages.append(choice.message)
            for tc in choice.message.tool_calls:
                args = json.loads(tc.function.arguments)
                result = get_weather(**args)
                messages.append({
                    'role': 'tool',
                    'tool_call_id': tc.id,
                    'content': json.dumps(result),
                })
        elif choice.finish_reason == 'stop':
            return choice.message.content
        else:
            raise RuntimeError(f'Unexpected finish_reason: {choice.finish_reason}')

print(run_with_tools('What is the weather in Tokyo right now?'))

import json, redis
from openai import OpenAI

r      = redis.Redis()
client = OpenAI()

SYSTEM = (
    'You are a support agent for AcmeCloud. '
    'Escalate billing disputes to a human. '
    'For technical issues, attempt self-service resolution. '
    'Create a support ticket when the user requests it or you cannot resolve the issue.'
)

TOOLS = [{
    'type': 'function',
    'function': {
        'name': 'create_ticket',
        'description': 'Open a support ticket in the ticketing system.',
        'parameters': {
            'type': 'object',
            'properties': {
                'summary':  {'type': 'string'},
                'priority': {'type': 'string', 'enum': ['low', 'normal', 'high', 'urgent']},
            },
            'required': ['summary', 'priority'],
        },
    },
}]

def create_ticket(summary: str, priority: str) -> dict:
    # Real implementation calls Zendesk / Jira API
    return {'ticket_id': 'TKT-99123', 'summary': summary, 'priority': priority}

def handle_message(session_id: str, user_input: str) -> str:
    raw = r.lrange(f'history:{session_id}', -40, -1)  # last 20 turns
    messages = [json.loads(m) for m in raw]
    messages.append({'role': 'user', 'content': user_input})

    while True:
        resp = client.chat.completions.create(
            model='gpt-4o-mini',
            messages=[{'role': 'system', 'content': SYSTEM}] + messages,
            tools=TOOLS,
            tool_choice='auto',
            max_tokens=512,
            temperature=0.1,
        )
        choice = resp.choices[0]

        if choice.finish_reason == 'tool_calls':
            messages.append(choice.message)
            for tc in choice.message.tool_calls:
                result = create_ticket(**json.loads(tc.function.arguments))
                messages.append({
                    'role': 'tool',
                    'tool_call_id': tc.id,
                    'content': json.dumps(result),
                })
        else:
            reply = choice.message.content
            messages.append({'role': 'assistant', 'content': reply})
            # Persist history to Redis with 1-hour TTL
            pipe = r.pipeline()
            pipe.delete(f'history:{session_id}')
            for m in messages:
                pipe.rpush(f'history:{session_id}', json.dumps(m))
            pipe.expire(f'history:{session_id}', 3600)
            pipe.execute()
            return reply
